1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	const parseCell = (key: string): Cell => {
11	  const [x, y] = key.split(",").map(Number);
12	  return [x, y];
13	};
14	
15	function countNeighbors(livingCells: Cell[]): Map<string, number> {
16	  const counts = new Map<string, number>();
17	  for (const [x, y] of livingCells) {
18	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
19	      const key = cellKey([x + dx, y + dy]);
20	      counts.set(key, (counts.get(key) ?? 0) + 1);
21	    }
22	  }
23	  return counts;
24	}
25	
26	const survives = (count: number, wasAlive: boolean): boolean =>
27	  count === 3 || (count === 2 && wasAlive);
28	
29	export function nextGeneration(livingCells: Cell[]): Cell[] {
30	  const liveSet = new Set(livingCells.map(cellKey));
31	  const neighborCounts = countNeighbors(livingCells);
32	
33	  const nextLivingCells: Cell[] = [];
34	  for (const [key, count] of neighborCounts) {
35	    if (survives(count, liveSet.has(key))) {
36	      nextLivingCells.push(parseCell(key));
37	    }
38	  }
39	  return nextLivingCells;
40	}
